
// SRV_PROXY
const _SRV=(window.location.protocol!=='file:');let _cache={},_pending={},_stimer=null;
const _SESSION_ONLY={'pm_current_user':1,'pm_master_unlocked':1};
function _flush(){const d=Object.assign({},_pending);_pending={};if(!Object.keys(d).length)return;delete d.pm_projects;if(!Object.keys(d).length)return;fetch('/api/smart-sync',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({data:d})}).catch(()=>{});}
function _sched(k,v){_pending[k]=v;clearTimeout(_stimer);_stimer=setTimeout(_flush,200);}
const _og=Storage.prototype.getItem,_os=Storage.prototype.setItem,_or=Storage.prototype.removeItem;
async function _loadSrv(){if(!_SRV)return;try{const r=await fetch('/api/data');const j=await r.json();if(j.ok&&j.data){Object.entries(j.data).forEach(([k,v])=>{if(k==='pm_lang'||_SESSION_ONLY[k])return;_cache[k]=typeof v==='string'?v:JSON.stringify(v);try{_os.call(localStorage,k,_cache[k]);}catch(e){}});}}catch(e){}}
Storage.prototype.getItem=function(k){if(_SRV&&k&&k.startsWith('pm_')&&k!=='pm_tl_cache'&&!_SESSION_ONLY[k]&&Object.prototype.hasOwnProperty.call(_cache,k))return _cache[k];return _og.call(this,k);};
Storage.prototype.setItem=function(k,v){_os.call(this,k,v);if(_SRV&&k&&k.startsWith('pm_')&&k!=='pm_tl_cache'&&k!=='pm_lang'&&k!=='pm_projects'&&k!=='pm_users'&&!_SESSION_ONLY[k]){_cache[k]=v;let p;try{p=JSON.parse(v);}catch(e){p=v;}_sched(k,p);}};
Storage.prototype.removeItem=function(k){_or.call(this,k);if(_SRV&&k&&k.startsWith('pm_')&&!_SESSION_ONLY[k]){delete _cache[k];fetch('/api/data/'+k,{method:'DELETE'}).catch(()=>{});}};
_loadSrv();
// ── SEED DATA LOADER ──────────────────────────────────────
(function(){
  try {
    const el=document.getElementById('APP_SEED_DATA');
    if(!el)return;
    const raw=el.textContent.replace('/* SEED:','').replace(' */','').trim();
    if(!raw||raw==='null')return;
    const seed=JSON.parse(raw);
    if(!seed||typeof seed!=='object')return;
    // دايماً احفظ — هذا الملف هو نسخة الحفظ الرسمية
    Object.entries(seed).forEach(([k,v])=>{
      if(k.startsWith('pm_')&&k!=='pm_tl_cache')
        localStorage.setItem(k,typeof v==='string'?v:JSON.stringify(v));
    });
  }catch(e){console.warn('Seed load failed',e);}
})();
