function _getRalHex(colorName) {
  if(!colorName) return null;
  var m = colorName.match(/RAL\s*(\d{4})/i);
  if(!m) return null;
  return _ralHexMap[m[1]] || null;
}

function _ralSwatchHTML(colorName, size) {
  var sz = size || 16;
  var hex = _getRalHex(colorName);
  if(!hex) return '';
  return '<span style="display:inline-block;width:'+sz+'px;height:'+sz+'px;border-radius:3px;background:'+hex+';border:1px solid rgba(0,0,0,0.15);flex-shrink:0;vertical-align:middle"></span>';
}

