function _getGlassHex(colorName) {
  if(!colorName) return null;
  var cn = colorName.toLowerCase();
  // exact full-name match first (HD Plus before HD)
  for(var k in _glassHexMap) { if(cn === k) return _glassHexMap[k]; }
  // longest substring match to avoid HD matching before HD Plus
  var best = null, bestLen = 0;
  for(var k in _glassHexMap) {
    if(cn.indexOf(k) !== -1 && k.length > bestLen) { best = _glassHexMap[k]; bestLen = k.length; }
  }
  return best;
}

function _glassSwatchHTML(colorName, size) {
  var sz = size || 16;
  var hex = _getGlassHex(colorName);
  if(!hex) return '';
  var isTransparent = colorName && (colorName.indexOf('شفاف') !== -1 || colorName.toLowerCase().indexOf('clear') !== -1);
  var extra = isTransparent ? 'opacity:0.7;' : '';
  return '<span style="display:inline-block;width:'+sz+'px;height:'+sz+'px;border-radius:3px;background:'+hex+';border:1px solid rgba(0,0,0,0.18);flex-shrink:0;vertical-align:middle;'+extra+'"></span>';
}

function _attachGlassSwatchToSelect(selId) {
  var sel = document.getElementById(selId); if(!sel) return;
  var swId = selId + '_gswatch';
  var sw = document.getElementById(swId);
  if(!sw) {
    sw = document.createElement('span'); sw.id = swId;
    sw.style.cssText = 'display:inline-block;width:18px;height:18px;border-radius:4px;border:1px solid rgba(0,0,0,0.18);vertical-align:middle;flex-shrink:0';
    var wrap = sel.parentElement;
    if(wrap && wrap.style.display !== 'flex') {
      wrap.style.display = 'flex'; wrap.style.alignItems = 'center'; wrap.style.gap = '6px';
    }
    sel.after(sw);
  }
  var hex = _getGlassHex(sel.value);
  if(hex) { sw.style.background = hex; sw.style.display = 'inline-block'; }
  else { sw.style.display = 'none'; }
  sel.onchange = function() { _attachGlassSwatchToSelect(selId); };
}

function _attachSwatchToSelect(selId) {
  var sel = document.getElementById(selId); if(!sel) return;
  var swId = selId + '_swatch';
  var sw = document.getElementById(swId);
  if(!sw) {
    sw = document.createElement('span'); sw.id = swId;
    sw.style.cssText = 'display:inline-block;width:18px;height:18px;border-radius:4px;border:1px solid rgba(0,0,0,0.15);vertical-align:middle;flex-shrink:0';
    var wrap = sel.parentElement;
    if(wrap && wrap.style.display !== 'flex') {
      wrap.style.display = 'flex'; wrap.style.alignItems = 'center'; wrap.style.gap = '6px';
    }
    sel.after(sw);
  }
  var hex = _getRalHex(sel.value);
  if(hex) { sw.style.background = hex; sw.style.display = 'inline-block'; }
  else { sw.style.display = 'none'; }
  sel.onchange = function() { _attachSwatchToSelect(selId); };
}
